'use client';

import Script from 'next/script';

const HTML = `
<div class="app">

<!-- FORM -->
<div class="form-col">
  <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:2px">
    <div>
      <h1>Aruma Invoice</h1>
      <p class="sub">Live preview · Print / Save as PDF</p>
    </div>
    <a href="/invoices" style="font-size:10px;color:#999;text-decoration:none;margin-top:6px">History →</a>
  </div>

  <div class="sec">Invoice Info</div>
  <div class="f"><label>Invoice Number</label><input id="invNum" value="INV-2026-06-001" oninput="upd()"></div>
  <div class="row2">
    <div class="f"><label>Date Issued</label><input type="date" id="dateIssued" oninput="upd()"></div>
    <div class="f"><label>Due Date</label><input type="date" id="dateDue" oninput="upd()"></div>
  </div>

  <div class="sec">Bill To</div>
  <div id="clientSelectorWrap" style="margin-bottom:10px;display:none">
    <label style="display:block;font-size:10.5px;color:#666;font-weight:500;margin-bottom:3px">Load saved client</label>
    <div style="display:flex;gap:6px">
      <select id="clientSelect" style="flex:1;padding:7px 9px;border:1px solid #ddd;border-radius:5px;font-size:12px;font-family:inherit;color:#1a1a1a;background:#fafafa">
        <option value="">— Select client —</option>
      </select>
      <button onclick="loadClient()" style="padding:7px 12px;background:#f0f0f0;border:1px solid #ddd;border-radius:5px;font-size:11px;font-weight:600;cursor:pointer;color:#444;white-space:nowrap">Load</button>
    </div>
  </div>
  <div class="f"><label>Client Name</label><input id="billTo" placeholder="Full name" oninput="upd()"></div>
  <div class="f"><label>Company Name <span style="font-weight:400;color:#bbb">(optional)</span></label><input id="billCompany" placeholder="PT / CV / LLC name" oninput="upd()"></div>
  <div class="f"><label>NPWP <span style="font-weight:400;color:#bbb">(optional)</span></label><input id="billNpwp" placeholder="e.g. 01.234.567.8-901.000" oninput="upd()"></div>
  <div class="f"><label>Client Email <span style="font-weight:400;color:#bbb">(for sending)</span></label><input type="email" id="billEmail" placeholder="client@email.com"></div>
  <label id="saveClientLabel" style="display:none;align-items:center;gap:6px;font-size:11px;color:#666;margin-bottom:10px;cursor:pointer">
    <input type="checkbox" id="saveClientCheck"> Save as new client
  </label>

  <div class="sec">Payments Received</div>
  <div id="paidWrap"></div>
  <button class="add-item" onclick="addPaidItem()" style="margin-bottom:14px">+ Add received payment</button>

  <div class="sec">Payment Line Items</div>
  <div id="itemsWrap"></div>
  <button class="add-item" onclick="addItem()">+ Add payment line</button>

  <div class="sec">Payment Terms</div>
  <div id="termsWrap"></div>
  <button class="add-term" onclick="addTerm()">+ Add term</button>

  <div class="actions">
    <div id="statusMsg" style="display:none;font-size:11px;text-align:center;padding:5px 8px;border-radius:5px;margin-bottom:4px"></div>
    <button id="btnSave" class="btn-print" style="background:#2563eb" onclick="saveInvoice()">Save Invoice</button>
    <button id="btnSend" class="btn-print" style="background:#059669" onclick="sendInvoice()">Send to Client</button>
    <button class="btn-print" onclick="downloadPDF()">⬇ Download as PDF</button>
    <button class="btn-print" style="background:#444" onclick="window.print()">🖨 Print</button>
    <button class="btn-reset" onclick="resetAll()">Reset form</button>
  </div>
</div>

<!-- PREVIEW -->
<div class="preview-col">
  <div class="inv">
    <img class="inv-wm" src="data:image/png;base64," alt="">
    <div class="inv-body">

      <div class="inv-top">
        <img class="inv-logo" src="data:image/png;base64," alt="Aruma">
        <div class="inv-meta">
          <div class="inum" id="p-num">—</div>
          <div>Date Issued: <span id="p-di">—</span></div>
          <div>Due Date: <span id="p-dd">—</span></div>
        </div>
      </div>

      <div class="inv-addr">
        PT Aruma Rezeki Bersama<br>
        Jl. Kayu Tulang No,82<br>
        Canggu, Kuta Utara,<br>
        Kab, Badung, Bali
      </div>

      <div class="inv-bill">
        <div class="lbl">BILL TO:</div>
        <div class="val" id="p-bill">—</div>
        <div class="val" id="p-bill-company" style="display:none;color:#666;font-size:7pt;margin-top:0.5mm"></div>
        <div class="val" id="p-bill-npwp" style="display:none;color:#888;font-size:6.5pt;margin-top:0.5mm"></div>
      </div>

      <table class="inv-tbl">
        <tr class="th"><td>DESCRIPTION</td><td>AMOUNT</td></tr>
        <tbody id="p-items"></tbody>
        <tbody id="p-paid-rows"></tbody>
      </table>

      <div class="inv-summary">
        <div class="inv-summary-row subtotal" id="p-subtotal-row" style="display:none">
          <span>Subtotal</span>
          <span id="p-subtotal">—</span>
        </div>
        <div class="inv-summary-row balance">
          <span>Balance Due</span>
          <span id="p-balance">—</span>
        </div>
        <div id="p-due-breakdown"></div>
      </div>

      <div class="inv-terms">
        <div class="lbl">Payment Term :</div>
        <ul id="p-terms"></ul>
      </div>

      <div class="inv-bank">
        <table>
          <tr><td>Bank</td><td>Mandiri</td></tr>
          <tr><td>Account Name</td><td>PT. Aruma Rezeki Bersama</td></tr>
          <tr><td>Swift Code</td><td>BMRIIDJAXXX</td></tr>
          <tr><td>Account Number</td><td>175-00-0398918-2</td></tr>
        </table>
      </div>

    </div>
  </div>
</div>

</div>
`;

const JS = `
let ic = 0, tc = 0, pc = 0;
let _savedId = null;
let _clients = [];

function fmtIDR(n) {
  return "IDR " + n.toLocaleString("id-ID");
}
function fmtDate(d) {
  if (!d) return "—";
  return new Date(d + "T00:00:00").toLocaleDateString("en-GB", { day: "numeric", month: "long", year: "numeric" });
}

function addItem(desc="", amt="", due="signing") {
  const id = "item_" + (++ic);
  const wrap = document.getElementById("itemsWrap");
  const div = document.createElement("div");
  div.className = "item-card"; div.id = id;
  div.innerHTML = \`
    <div class="item-header">
      <span class="item-label">Item \${ic}</span>
      <button class="rm-item" onclick="document.getElementById('\${id}').remove();upd()">×</button>
    </div>
    <div class="f"><label>Description</label>
      <textarea placeholder="e.g. Year 1 Lease Balance — Unit 2&#10;Jl. Pantai Mengening, Cemagi, Bali&#10;Due on signing" oninput="upd()">\${desc}</textarea>
    </div>
    <div class="f"><label>Amount (IDR)</label>
      <input type="number" placeholder="e.g. 234000000" oninput="upd()" value="\${amt}">
    </div>
    <div class="f"><label>When is this due?</label>
      <select onchange="upd()">
        <option value="signing" \${due==="signing"?"selected":""}>Due on signing</option>
        <option value="15days" \${due==="15days"?"selected":""}>Due within 15 days</option>
        <option value="annual" \${due==="annual"?"selected":""}>Annual payment</option>
        <option value="">— No label —</option>
      </select>
    </div>\`;
  wrap.appendChild(div);
  upd();
}

function addPaidItem(desc="", amt="") {
  const id = "paid_" + (++pc);
  const wrap = document.getElementById("paidWrap");
  const div = document.createElement("div");
  div.className = "item-card"; div.id = id;
  div.innerHTML = \`
    <div class="item-header">
      <span class="item-label">Payment Received \${pc}</span>
      <button class="rm-item" onclick="document.getElementById('\${id}').remove();upd()">×</button>
    </div>
    <div class="f"><label>Description</label>
      <textarea placeholder="e.g. Reservation deposit" oninput="upd()">\${desc}</textarea>
    </div>
    <div class="f"><label>Amount (IDR)</label>
      <input type="number" placeholder="0" min="0" step="1000000" oninput="upd()" value="\${amt}">
    </div>\`;
  wrap.appendChild(div);
  upd();
}

function addTerm(val="") {
  const id = "term_" + (++tc);
  const wrap = document.getElementById("termsWrap");
  const div = document.createElement("div");
  div.className = "term-row"; div.id = id;
  div.innerHTML = \`<textarea placeholder="Payment term..." oninput="upd()">\${val}</textarea>
    <button class="rm" onclick="document.getElementById('\${id}').remove();upd()">×</button>\`;
  wrap.appendChild(div);
  upd();
}

const DUE_LABELS = { signing: "Due on signing", "15days": "Due within 15 days", annual: "Annual payment" };
const DUE_CLASS  = { signing: "due-signing", "15days": "due-15days", annual: "" };

function upd() {
  document.getElementById("p-num").textContent  = document.getElementById("invNum").value || "—";
  document.getElementById("p-di").textContent   = fmtDate(document.getElementById("dateIssued").value);
  document.getElementById("p-dd").textContent   = fmtDate(document.getElementById("dateDue").value);
  document.getElementById("p-bill").textContent = document.getElementById("billTo").value || "—";
  const company = document.getElementById("billCompany").value.trim();
  const npwp    = document.getElementById("billNpwp").value.trim();
  const elComp  = document.getElementById("p-bill-company");
  const elNpwp  = document.getElementById("p-bill-npwp");
  elComp.style.display = company ? "" : "none"; elComp.textContent = company;
  elNpwp.style.display = npwp    ? "" : "none"; elNpwp.textContent = npwp ? "NPWP: " + npwp : "";

  const tbody = document.getElementById("p-items");
  tbody.innerHTML = "";
  let total = 0;
  const byDue = { signing: 0, "15days": 0, annual: 0 };
  document.querySelectorAll("#itemsWrap .item-card").forEach(card => {
    const desc  = card.querySelector("textarea").value.trim();
    const amt   = parseFloat(card.querySelector("input[type=number]").value) || 0;
    const due   = card.querySelector("select").value;
    if (!desc && !amt) return;
    total += amt;
    if (due in byDue) byDue[due] += amt;
    const lines = desc ? desc.split("\\n").filter(Boolean) : ["—"];
    const dueLabel = DUE_LABELS[due] || "";
    const dueClass = DUE_CLASS[due] || "";
    const tr = document.createElement("tr");
    tr.className = "inv-item";
    tr.innerHTML = \`<td>\${lines.map((l,i)=>i===0?\`<strong>\${l}</strong>\`:l).join("<br>")}
      \${dueLabel ? \`<div><span class="due-badge \${dueClass}">\${dueLabel}</span></div>\` : ""}
      </td>
      <td>\${amt ? fmtIDR(amt) : "—"}</td>\`;
    tbody.appendChild(tr);
  });

  let totalPaid = 0;
  const paidTbody = document.getElementById("p-paid-rows");
  paidTbody.innerHTML = "";
  const paidCards = document.querySelectorAll("#paidWrap .item-card");
  paidCards.forEach(card => {
    const inputs    = card.querySelectorAll("input[type=number]");
    const textareas = card.querySelectorAll("textarea");
    const pAmt  = parseFloat(inputs[0]?.value) || 0;
    const pDesc = textareas[0]?.value.trim() || "Payment received";
    totalPaid += pAmt;
    const tr = document.createElement("tr");
    tr.className = "inv-deduct";
    tr.innerHTML = \`<td>Less: \${pDesc}</td><td>\${pAmt ? "("+fmtIDR(pAmt)+")" : "—"}</td>\`;
    paidTbody.appendChild(tr);
  });

  const hasPaid    = paidCards.length > 0;
  const multiDue   = Object.values(byDue).filter(v => v > 0).length > 1;
  const balanceDue = total - totalPaid;

  document.getElementById("p-subtotal-row").style.display = (hasPaid || multiDue) ? "" : "none";
  document.getElementById("p-subtotal").textContent = total ? fmtIDR(total) : "—";
  document.getElementById("p-balance").textContent  = total ? fmtIDR(Math.max(0, hasPaid ? balanceDue : total)) : "—";

  const breakdown = document.getElementById("p-due-breakdown");
  breakdown.innerHTML = "";
  if (total && multiDue) {
    const divider = document.createElement("div");
    divider.className = "inv-summary-divider";
    breakdown.appendChild(divider);
    let remainingPaid = totalPaid;
    const netByDue = {};
    ["signing", "15days", "annual"].forEach(key => {
      const gross = byDue[key] || 0;
      const deducted = Math.min(gross, remainingPaid);
      remainingPaid -= deducted;
      netByDue[key] = gross - deducted;
    });
    [{ key:"signing", label:"Due on Signing", cls:"due-now" }, { key:"15days", label:"Due in 15 Days", cls:"due-later" }, { key:"annual", label:"Annual Payment", cls:"due-later" }].forEach(({ key, label, cls }) => {
      if (!byDue[key]) return;
      const row = document.createElement("div");
      row.className = "inv-summary-row " + cls;
      row.innerHTML = \`<span>\${label}</span><span>\${fmtIDR(netByDue[key])}</span>\`;
      breakdown.appendChild(row);
    });
  }

  const ul = document.getElementById("p-terms");
  ul.innerHTML = "";
  document.querySelectorAll(".term-row textarea").forEach(ta => {
    const t = ta.value.trim();
    if (t) { const li = document.createElement("li"); li.textContent = t; ul.appendChild(li); }
  });

  // Show save-client checkbox when client name is filled
  const billTo = document.getElementById("billTo").value.trim();
  const lbl = document.getElementById("saveClientLabel");
  if (lbl) lbl.style.display = billTo ? "flex" : "none";
}

function downloadPDF() {
  const invNum = document.getElementById("invNum").value.trim();
  const client = document.getElementById("billTo").value.trim();
  const parts = ["Aruma-Invoice"];
  if (invNum) parts.push(invNum);
  if (client) parts.push(client.replace(/\\s+/g, "-"));
  const origTitle = document.title;
  document.title = parts.join("_");
  window.print();
  document.title = origTitle;
}

function resetAll() {
  if (!confirm("Reset everything?")) return;
  ["invNum","billTo","billCompany","billNpwp","billEmail"].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.value = "";
  });
  document.getElementById("itemsWrap").innerHTML = "";
  document.getElementById("paidWrap").innerHTML = "";
  document.getElementById("termsWrap").innerHTML = "";
  ic = 0; tc = 0; pc = 0;
  _savedId = null;
  document.getElementById("btnSave").textContent = "Save Invoice";
  addItem(); addTerm();
  upd();
}

// ── Backend: collect form data ──────────────────────────────────────────────

function collectItems() {
  const items = [];
  document.querySelectorAll("#itemsWrap .item-card").forEach(card => {
    items.push({
      desc:   card.querySelector("textarea").value.trim(),
      amount: card.querySelector("input[type=number]").value,
      due:    card.querySelector("select").value,
    });
  });
  return items;
}

function collectPaidItems() {
  const paid = [];
  document.querySelectorAll("#paidWrap .item-card").forEach(card => {
    const inputs = card.querySelectorAll("input[type=number]");
    const textareas = card.querySelectorAll("textarea");
    paid.push({ desc: textareas[0]?.value.trim() || "", amount: inputs[0]?.value || "0" });
  });
  return paid;
}

function collectTerms() {
  return Array.from(document.querySelectorAll(".term-row textarea")).map(ta => ta.value.trim()).filter(Boolean);
}

function calcTotal() {
  let total = 0;
  document.querySelectorAll("#itemsWrap .item-card input[type=number]").forEach(inp => { total += parseFloat(inp.value) || 0; });
  return total;
}

function showStatus(msg, ok) {
  const el = document.getElementById("statusMsg");
  el.textContent = msg;
  el.style.display = "block";
  el.style.background = ok ? "#ecfdf5" : "#fef2f2";
  el.style.color = ok ? "#059669" : "#dc2626";
  setTimeout(() => { el.style.display = "none"; }, 4000);
}

// ── Backend: save invoice ───────────────────────────────────────────────────

async function saveInvoice() {
  const btn = document.getElementById("btnSave");
  btn.disabled = true; btn.textContent = "Saving…";
  try {
    const payload = {
      invoiceNumber: document.getElementById("invNum").value,
      dateIssued:    document.getElementById("dateIssued").value,
      dateDue:       document.getElementById("dateDue").value,
      billTo:        document.getElementById("billTo").value,
      billCompany:   document.getElementById("billCompany").value,
      billNpwp:      document.getElementById("billNpwp").value,
      billEmail:     document.getElementById("billEmail")?.value || "",
      items:     collectItems(),
      paidItems: collectPaidItems(),
      terms:     collectTerms(),
      total:     calcTotal(),
    };

    let res;
    if (_savedId) {
      res = await fetch("/api/invoices/" + _savedId, { method:"PUT", headers:{"Content-Type":"application/json"}, body: JSON.stringify(payload) });
    } else {
      res = await fetch("/api/invoices", { method:"POST", headers:{"Content-Type":"application/json"}, body: JSON.stringify(payload) });
      if (res.ok) {
        const data = await res.json();
        _savedId = data.id;
        if (data.invoiceNumber && !document.getElementById("invNum").value) {
          document.getElementById("invNum").value = data.invoiceNumber;
          upd();
        }
      }
    }

    // Optionally save client
    const saveClientCheck = document.getElementById("saveClientCheck");
    if (saveClientCheck?.checked && document.getElementById("billTo").value.trim()) {
      await fetch("/api/clients", {
        method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({
          name:    document.getElementById("billTo").value,
          company: document.getElementById("billCompany").value,
          npwp:    document.getElementById("billNpwp").value,
          email:   document.getElementById("billEmail")?.value || "",
        })
      });
      saveClientCheck.checked = false;
      loadClientsDropdown();
    }

    btn.textContent = "Update Invoice";
    showStatus("Saved.", true);
  } catch(e) {
    showStatus("Save failed.", false);
  } finally {
    btn.disabled = false;
  }
}

// ── Backend: send invoice ───────────────────────────────────────────────────

async function sendInvoice() {
  if (!_savedId) { showStatus("Save the invoice first.", false); return; }
  const email = document.getElementById("billEmail")?.value?.trim();
  if (!email) { showStatus("Add client email before sending.", false); return; }
  const btn = document.getElementById("btnSend");
  btn.disabled = true; btn.textContent = "Sending…";
  try {
    const res = await fetch("/api/invoices/" + _savedId + "/send", { method:"POST" });
    const data = await res.json();
    if (!res.ok) { showStatus(data.error || "Send failed.", false); return; }
    showStatus("Sent to " + email + ".", true);
  } catch(e) {
    showStatus("Send failed.", false);
  } finally {
    btn.disabled = false; btn.textContent = "Send to Client";
  }
}

// ── Backend: client dropdown ────────────────────────────────────────────────

async function loadClientsDropdown() {
  try {
    const clients = await fetch("/api/clients").then(r => r.json());
    _clients = clients;
    const wrap = document.getElementById("clientSelectorWrap");
    const sel  = document.getElementById("clientSelect");
    if (!clients.length) { wrap.style.display = "none"; return; }
    wrap.style.display = "block";
    sel.innerHTML = '<option value="">— Select client —</option>';
    clients.forEach(c => {
      const opt = document.createElement("option");
      opt.value = c.id;
      opt.textContent = c.name + (c.company ? " (" + c.company + ")" : "");
      sel.appendChild(opt);
    });
  } catch(e) {}
}

function loadClient() {
  const id = document.getElementById("clientSelect").value;
  const c = _clients.find(x => x.id === id);
  if (!c) return;
  document.getElementById("billTo").value      = c.name;
  document.getElementById("billCompany").value = c.company;
  document.getElementById("billNpwp").value    = c.npwp;
  const emailEl = document.getElementById("billEmail");
  if (emailEl) emailEl.value = c.email;
  upd();
}

// ── Init ────────────────────────────────────────────────────────────────────

window.addEventListener("DOMContentLoaded", () => {
  const today = new Date().toISOString().split("T")[0];
  document.getElementById("dateIssued").value = today;
  document.getElementById("dateDue").value = today;
  addItem("Year 1 Lease Balance — [Property]\\nJl. Pantai Mengening, Cemagi, Bali\\nLease term: [dates]\\nReservation deposit deducted from Year 1", "", "signing");
  addItem("Year 2 Rent + Security Deposit\\nYear 2 rent: IDR —\\nSecurity deposit (10% of annual): IDR —", "", "15days");
  addTerm("Reservation deposit previously paid: IDR — — deducted from Year 1 rent.");
  addTerm("Total due on signing: IDR —.");
  addTerm("All payments subject to the terms and conditions of the Lease Agreement.");
  upd();
  loadClientsDropdown();
});
`;

export default function Page() {
  return (
    <>
      <div dangerouslySetInnerHTML={{ __html: HTML }} />
      <Script id="invoice-js" strategy="afterInteractive">
        {JS}
      </Script>
    </>
  );
}
